// src/hooks/useTransactions.js
// Centraliza todo el estado y lógica de transacciones.
// Las páginas solo llaman a este hook — no hacen fetch directamente.

import { useState, useEffect, useCallback } from 'react'
import {
  getTransactions,
  createTransaction,
  deleteTransaction,
  getSummary,
} from '../api/transactionApi'

export const useTransactions = (filters = {}) => {
  const [transactions, setTransactions] = useState([])
  const [summary,      setSummary]      = useState(null)
  const [loading,      setLoading]      = useState(true)
  const [error,        setError]        = useState(null)

  // ── Cargar transacciones y resumen ───────────────────────────────
  const load = useCallback(async () => {
    setLoading(true)
    setError(null)
    try {
      const [txRes, sumRes] = await Promise.all([
        getTransactions(filters),
        getSummary(),
      ])
      setTransactions(txRes.data   || [])
      setSummary(sumRes.data       || null)
    } catch (err) {
      setError(err.response?.data?.error || 'Error cargando los datos')
    } finally {
      setLoading(false)
    }
  }, [JSON.stringify(filters)])

  useEffect(() => { load() }, [load])

  // ── Agregar transacción ──────────────────────────────────────────
  const addTransaction = async (payload) => {
    const res = await createTransaction(payload)
    await load() // Recargar para tener datos frescos
    return res
  }

  // ── Eliminar transacción ─────────────────────────────────────────
  const removeTransaction = async (id) => {
    await deleteTransaction(id)
    setTransactions((prev) => prev.filter((t) => t.id !== id))
    await getSummary().then((res) => setSummary(res.data))
  }

  return { transactions, summary, loading, error, addTransaction, removeTransaction, reload: load }
}
